 1→package middleware
 2→
 3→import (
 4→	"log/slog"
 5→	"net/http"
 6→	"time"
 7→)
 8→
 9→// responseWriter wraps http.ResponseWriter to capture the status code.
10→type responseWriter struct {
11→	http.ResponseWriter
12→	status int
13→	bytes  int
14→}
15→
16→func (rw *responseWriter) WriteHeader(status int) {
17→	rw.status = status
18→	rw.ResponseWriter.WriteHeader(status)
19→}
20→
21→func (rw *responseWriter) Write(b []byte) (int, error) {
22→	n, err := rw.ResponseWriter.Write(b)
23→	rw.bytes += n
24→	return n, err
25→}
26→
27→// Logging logs each request with method, path, status, duration, and request ID.
28→func Logging(next http.Handler) http.Handler {
29→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
30→		start := time.Now()
31→		rw := &responseWriter{ResponseWriter: w, status: http.StatusOK}
32→
33→		next.ServeHTTP(rw, r)
34→
35→		attrs := []any{
36→			"method", r.Method,
37→			"path", r.URL.Path,
38→			"status", rw.status,
39→			"duration_ms", time.Since(start).Milliseconds(),
40→			"bytes", rw.bytes,
41→			"request_id", requestIDFromContext(r.Context()),
42→			"remote_addr", r.RemoteAddr,
43→		}
44→		if q := r.URL.RawQuery; q != "" {
45→			attrs = append(attrs, "query", q)
46→		}
47→		if ua := r.UserAgent(); ua != "" {
48→			attrs = append(attrs, "user_agent", ua)
49→		}
50→		slog.InfoContext(r.Context(), "request", attrs...)
51→	})
52→}
53→

 1→package middleware
 2→
 3→import (
 4→	"fmt"
 5→	"net"
 6→	"net/http"
 7→	"strings"
 8→)
 9→
10→// IPAllowlist returns middleware that restricts access to the given CIDR ranges.
11→// Requests from IPs not in any CIDR receive 403 Forbidden.
12→func IPAllowlist(cidrs []*net.IPNet) func(http.Handler) http.Handler {
13→	return func(next http.Handler) http.Handler {
14→		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
15→			ip := clientIP(r)
16→			if ip == nil || !matchesCIDR(ip, cidrs) {
17→				http.Error(w, "forbidden", http.StatusForbidden)
18→				return
19→			}
20→			next.ServeHTTP(w, r)
21→		})
22→	}
23→}
24→
25→// ParseCIDRs splits a comma-separated list of CIDR strings and parses each one.
26→func ParseCIDRs(raw string) ([]*net.IPNet, error) {
27→	var nets []*net.IPNet
28→	for _, s := range strings.Split(raw, ",") {
29→		s = strings.TrimSpace(s)
30→		if s == "" {
31→			continue
32→		}
33→		_, ipNet, err := net.ParseCIDR(s)
34→		if err != nil {
35→			return nil, fmt.Errorf("middleware: invalid CIDR %q: %w", s, err)
36→		}
37→		nets = append(nets, ipNet)
38→	}
39→	return nets, nil
40→}
41→
42→// clientIP extracts the client IP from the request. It uses RemoteAddr,
43→// which chi's RealIP middleware has already resolved from X-Forwarded-For
44→// or X-Real-IP headers.
45→func clientIP(r *http.Request) net.IP {
46→	host, _, err := net.SplitHostPort(r.RemoteAddr)
47→	if err != nil {
48→		// RemoteAddr might be an IP without port
49→		return net.ParseIP(r.RemoteAddr)
50→	}
51→	return net.ParseIP(host)
52→}
53→
54→func matchesCIDR(ip net.IP, cidrs []*net.IPNet) bool {
55→	for _, cidr := range cidrs {
56→		if cidr.Contains(ip) {
57→			return true
58→		}
59→	}
60→	return false
61→}
62→

 1→package middleware
 2→
 3→import "context"
 4→
 5→type requestIDKey struct{}
 6→
 7→func withRequestID(ctx context.Context, id string) context.Context {
 8→	return context.WithValue(ctx, requestIDKey{}, id)
 9→}
10→
11→func requestIDFromContext(ctx context.Context) string {
12→	id, _ := ctx.Value(requestIDKey{}).(string)
13→	return id
14→}
