  1→package router_test
  2→
  3→import (
  4→	"crypto/rand"
  5→	"crypto/rsa"
  6→	"crypto/x509"
  7→	"encoding/pem"
  8→	"net"
  9→	"net/http"
 10→	"net/http/httptest"
 11→	"strings"
 12→	"testing"
 13→
 14→	"github.com/ketang/kapow/api/internal/auth"
 15→	"github.com/ketang/kapow/api/internal/config"
 16→	"github.com/ketang/kapow/api/internal/router"
 17→	"github.com/ketang/kapow/api/internal/search"
 18→)
 19→
 20→// --- helpers ---
 21→
 22→// stubValidator implements auth.Validator for router-level tests.
 23→type stubValidator struct {
 24→	claims *auth.Claims
 25→	err    error
 26→}
 27→
 28→func (s *stubValidator) Validate(_ string) (*auth.Claims, error) {
 29→	return s.claims, s.err
 30→}
 31→
 32→// testConfig returns a minimal Config suitable for router construction.
 33→// Override fields via functional options.
 34→func testConfig(overrides ...func(*config.Config)) *config.Config {
 35→	cfg := &config.Config{
 36→		Env:                  "production",
 37→		GraphQLIntrospection: true,
 38→		MCPEnabled:           true,
 39→		RateLimitEnabled:     false,
 40→	}
 41→	for _, o := range overrides {
 42→		o(cfg)
 43→	}
 44→	return cfg
 45→}
 46→
 47→// testDeps builds router.Deps with nil DB and services.
 48→// Safe because router.New() doesn't query the DB during construction.
 49→func testDeps(cfg *config.Config, v auth.Validator) router.Deps {
 50→	return router.Deps{
 51→		Config:    cfg,
 52→		Validator: v,
 53→		Search:    search.NewRegistry(),
 54→	}
 55→}
 56→
 57→// selectValidator replicates the validator selection logic from cmd/server/main.go.
 58→// This makes the startup auth validation path testable without os.Exit.
 59→func selectValidator(jwtPublicKey, jwtSecret string) (auth.Validator, error) {
 60→	if jwtPublicKey != "" {
 61→		return auth.NewRSAValidator(jwtPublicKey)
 62→	}
 63→	return auth.NewHMACValidator(jwtSecret)
 64→}
 65→
 66→// generateRSAPEM creates a fresh RSA key pair and returns the PEM-encoded public key.
 67→func generateRSAPEM(t *testing.T) string {
 68→	t.Helper()
 69→	key, err := rsa.GenerateKey(rand.Reader, 2048)
 70→	if err != nil {
 71→		t.Fatalf("generate RSA key: %v", err)
 72→	}
 73→	pubBytes, err := x509.MarshalPKIXPublicKey(&key.PublicKey)
 74→	if err != nil {
 75→		t.Fatalf("marshal RSA public key: %v", err)
 76→	}
 77→	return string(pem.EncodeToMemory(&pem.Block{Type: "PUBLIC KEY", Bytes: pubBytes}))
 78→}
 79→
 80→// --- Group 1: Startup Auth Validation ---
 81→
 82→func TestValidatorSelection(t *testing.T) {
 83→	t.Parallel()
 84→	rsaPEM := generateRSAPEM(t)
 85→
 86→	tests := []struct {
 87→		name         string
 88→		jwtPublicKey string
 89→		jwtSecret    string
 90→		wantErr      bool
 91→		wantType     string // "hmac" or "rsa"
 92→	}{
 93→		{
 94→			name:    "both empty returns error",
 95→			wantErr: true,
 96→		},
 97→		{
 98→			name:      "whitespace secret returns error",
 99→			jwtSecret: "  \t\n",
100→			wantErr:   true,
101→		},
102→		{
103→			name:      "valid secret returns HMAC validator",
104→			jwtSecret: "test-secret-key",
105→			wantType:  "hmac",
106→		},
107→		{
108→			name:         "valid RSA PEM returns RSA validator",
109→			jwtPublicKey: rsaPEM,
110→			wantType:     "rsa",
111→		},
112→		{
113→			name:         "invalid RSA PEM returns error",
114→			jwtPublicKey: "not-a-valid-pem",
115→			wantErr:      true,
116→		},
117→		{
118→			name:         "RSA takes precedence over HMAC",
119→			jwtPublicKey: rsaPEM,
120→			jwtSecret:    "test-secret-key",
121→			wantType:     "rsa",
122→		},
123→	}
124→	for _, tt := range tests {
125→		t.Run(tt.name, func(t *testing.T) {
126→			t.Parallel()
127→			v, err := selectValidator(tt.jwtPublicKey, tt.jwtSecret)
128→			if tt.wantErr {
129→				if err == nil {
130→					t.Fatal("expected error, got nil")
131→				}
132→				return
133→			}
134→			if err != nil {
135→				t.Fatalf("unexpected error: %v", err)
136→			}
137→			switch tt.wantType {
138→			case "hmac":
139→				if _, ok := v.(*auth.HMACValidator); !ok {
