186→func TestRouteProtection(t *testing.T) {
187→	t.Parallel()
188→
189→	// Use a validator that rejects all tokens — lets us test both anonymous
190→	// pass-through (OptionalAuth) and mandatory rejection (Auth).
191→	failValidator := &stubValidator{err: http.ErrNotSupported}
192→
193→	cfg := testConfig(func(c *config.Config) { c.MCPEnabled = true })
194→	h := router.New(testDeps(cfg, failValidator))
195→
196→	tests := []struct {
197→		name       string
198→		method     string
199→		path       string
200→		authHeader string
201→		wantStatus int    // exact match; 0 means "not 401"
202→		wantNot    int    // status must NOT be this
203→		checkWWW   bool   // verify WWW-Authenticate header
204→	}{
205→		{
206→			name:    "graphql POST anonymous allowed",
207→			method:  "POST",
208→			path:    "/graphql",
209→			wantNot: http.StatusUnauthorized,
210→		},
211→		{
212→			name:    "graphql GET anonymous allowed",
213→			method:  "GET",
214→			path:    "/graphql",
215→			wantNot: http.StatusUnauthorized,
216→		},
217→		{
218→			name:       "graphql invalid token rejected",
219→			method:     "POST",
220→			path:       "/graphql",
221→			authHeader: "Bearer bad-token",
222→			wantStatus: http.StatusUnauthorized,
223→		},
224→		{
225→			name:    "export anonymous allowed",
226→			method:  "GET",
227→			path:    "/api/export/csv",
228→			wantNot: http.StatusUnauthorized,
229→		},
230→		{
231→			name:       "export invalid token rejected",
232→			method:     "GET",
233→			path:       "/api/export/csv",
234→			authHeader: "Bearer bad-token",
235→			wantStatus: http.StatusUnauthorized,
236→		},
237→		{
238→			name:       "mcp unauthenticated rejected",
239→			method:     "POST",
240→			path:       "/mcp/message",
241→			wantStatus: http.StatusUnauthorized,
242→			checkWWW:   true,
243→		},
244→		{
245→			name:       "mcp invalid token rejected",
246→			method:     "POST",
247→			path:       "/mcp/message",
248→			authHeader: "Bearer bad-token",
249→			wantStatus: http.StatusUnauthorized,
250→			checkWWW:   true,
251→		},
252→		{
253→			name:       "well-known no auth required",
254→			method:     "GET",
255→			path:       "/.well-known/oauth-protected-resource",
256→			wantStatus: http.StatusOK,
257→		},
258→	}
259→	for _, tt := range tests {
