261→			t.Parallel()
262→			req := httptest.NewRequest(tt.method, tt.path, nil)
263→			if tt.authHeader != "" {
264→				req.Header.Set("Authorization", tt.authHeader)
265→			}
266→			rr := httptest.NewRecorder()
267→			h.ServeHTTP(rr, req)
268→
269→			if tt.wantStatus != 0 && rr.Code != tt.wantStatus {
270→				t.Errorf("status = %d, want %d", rr.Code, tt.wantStatus)
271→			}
272→			if tt.wantNot != 0 && rr.Code == tt.wantNot {
273→				t.Errorf("status = %d, must not be %d", rr.Code, tt.wantNot)
274→			}
275→			if tt.checkWWW {
276→				wwwAuth := rr.Header().Get("WWW-Authenticate")
277→				if !strings.Contains(wwwAuth, "Bearer") {
278→					t.Errorf("WWW-Authenticate = %q, want Bearer", wwwAuth)
279→				}
280→				if !strings.Contains(wwwAuth, `resource_metadata="/.well-known/oauth-protected-resource"`) {
281→					t.Errorf("WWW-Authenticate = %q, want resource_metadata", wwwAuth)
282→				}
283→			}
284→		})
