package middleware_test

import (
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/ketang/kapow/api/internal/middleware"
)

func TestCORS(t *testing.T) {
	t.Parallel()

	okHandler := http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.WriteHeader(http.StatusOK)
	})

	tests := []struct {
		name           string
		origins        string
		method         string
		reqOrigin      string
		reqHeaders     map[string]string // extra headers on the request
		wantStatus     int
		wantACAO       string // expected Access-Control-Allow-Origin ("" means absent)
		wantACAM       string // expected Access-Control-Allow-Methods ("" means absent)
		wantVary       bool   // expect Vary: Origin
		wantNextCalled bool   // whether the downstream handler should be invoked
	}{
		{
			name:           "empty origins no-op",
			origins:        "",
			method:         "GET",
			reqOrigin:      "https://example.com",
			wantStatus:     http.StatusOK,
			wantNextCalled: true,
		},
		{
			name:           "whitespace-only origins no-op",
			origins:        "  , ,  ",
			method:         "GET",
			reqOrigin:      "https://example.com",
			wantStatus:     http.StatusOK,
			wantNextCalled: true,
		},
		{
			name:           "no Origin header passes through",
			origins:        "https://example.com",
			method:         "GET",
			wantStatus:     http.StatusOK,
			wantNextCalled: true,
		},
		{
			name:           "disallowed origin passes through without headers",
			origins:        "https://allowed.com",
			method:         "GET",
			reqOrigin:      "https://evil.com",
			wantStatus:     http.StatusOK,
			wantNextCalled: true,
		},
		{
			name:           "allowed origin on actual request",
			origins:        "https://allowed.com",
			method:         "POST",
			reqOrigin:      "https://allowed.com",
			wantStatus:     http.StatusOK,
			wantACAO:       "https://allowed.com",
			wantVary:       true,
			wantNextCalled: true,
		},
		{
			name:       "allowed origin preflight",
			origins:    "https://allowed.com",
			method:     "OPTIONS",
			reqOrigin:  "https://allowed.com",
			reqHeaders: map[string]string{"Access-Control-Request-Method": "POST"},
			wantStatus: http.StatusNoContent,
			wantACAO:   "https://allowed.com",
			wantACAM:   "GET, POST, PUT, DELETE, OPTIONS",
			wantVary:   true,
		},
		{
			name:       "disallowed origin preflight passes through",
			origins:    "https://allowed.com",
			method:     "OPTIONS",
			reqOrigin:  "https://evil.com",
			reqHeaders: map[string]string{"Access-Control-Request-Method": "POST"},
			wantStatus: http.StatusOK,
			wantNextCalled: true,
		},
		{
			name:           "multiple origins second matches",
			origins:        "https://first.com, https://second.com",
			method:         "GET",
			reqOrigin:      "https://second.com",
			wantStatus:     http.StatusOK,
			wantACAO:       "https://second.com",
			wantVary:       true,
			wantNextCalled: true,
		},
		{
			name:           "OPTIONS without Access-Control-Request-Method is not preflight",
			origins:        "https://allowed.com",
			method:         "OPTIONS",
			reqOrigin:      "https://allowed.com",
			wantStatus:     http.StatusOK,
			wantACAO:       "https://allowed.com",
			wantVary:       true,
			wantNextCalled: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()

			nextCalled := false
			inner := http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
				nextCalled = true
				w.WriteHeader(http.StatusOK)
			})
			_ = okHandler // keep import used

			handler := middleware.CORS(tt.origins)(inner)

			req := httptest.NewRequest(tt.method, "/test", nil)
			if tt.reqOrigin != "" {
				req.Header.Set("Origin", tt.reqOrigin)
			}
			for k, v := range tt.reqHeaders {
				req.Header.Set(k, v)
			}

			rr := httptest.NewRecorder()
			handler.ServeHTTP(rr, req)

			if rr.Code != tt.wantStatus {
				t.Errorf("status = %d, want %d", rr.Code, tt.wantStatus)
			}

			acao := rr.Header().Get("Access-Control-Allow-Origin")
			if acao != tt.wantACAO {
				t.Errorf("Access-Control-Allow-Origin = %q, want %q", acao, tt.wantACAO)
			}

			acam := rr.Header().Get("Access-Control-Allow-Methods")
			if acam != tt.wantACAM {
				t.Errorf("Access-Control-Allow-Methods = %q, want %q", acam, tt.wantACAM)
			}

			vary := rr.Header().Get("Vary")
			if tt.wantVary && vary != "Origin" {
				t.Errorf("Vary = %q, want %q", vary, "Origin")
			}
			if !tt.wantVary && vary == "Origin" {
				t.Errorf("unexpected Vary = %q", vary)
			}

			if tt.wantNextCalled && !nextCalled {
				t.Error("expected next handler to be called, but it was not")
			}
			if !tt.wantNextCalled && nextCalled {
				t.Error("expected next handler NOT to be called, but it was")
			}
		})
	}
}

