		req.Header.Set("Origin", allowed)
		req.Header.Set("Access-Control-Request-Method", "POST")
		rr := httptest.NewRecorder()
		h.ServeHTTP(rr, req)

		if rr.Code != http.StatusNoContent {
			t.Errorf("status = %d, want %d", rr.Code, http.StatusNoContent)
		}
		if acao := rr.Header().Get("Access-Control-Allow-Origin"); acao != allowed {
			t.Errorf("Access-Control-Allow-Origin = %q, want %q", acao, allowed)
		}
		if acam := rr.Header().Get("Access-Control-Allow-Methods"); acam == "" {
			t.Error("expected Access-Control-Allow-Methods header")
		}
		if rr.Header().Get("Access-Control-Max-Age") == "" {
			t.Error("expected Access-Control-Max-Age header")
		}
	})

	t.Run("actual request with allowed origin", func(t *testing.T) {
		t.Parallel()
		req := httptest.NewRequest("POST", "/graphql", nil)
		req.Header.Set("Origin", allowed)
		rr := httptest.NewRecorder()
		h.ServeHTTP(rr, req)

		if acao := rr.Header().Get("Access-Control-Allow-Origin"); acao != allowed {
			t.Errorf("Access-Control-Allow-Origin = %q, want %q", acao, allowed)
		}
		if rr.Header().Get("Vary") != "Origin" {
			t.Errorf("Vary = %q, want %q", rr.Header().Get("Vary"), "Origin")
		}
	})

	t.Run("disallowed origin gets no CORS headers", func(t *testing.T) {
		t.Parallel()
		req := httptest.NewRequest("POST", "/graphql", nil)
		req.Header.Set("Origin", "https://evil.example.com")
		rr := httptest.NewRecorder()
		h.ServeHTTP(rr, req)

		if acao := rr.Header().Get("Access-Control-Allow-Origin"); acao != "" {
			t.Errorf("unexpected Access-Control-Allow-Origin = %q", acao)
		}
	})

	t.Run("export route with allowed origin", func(t *testing.T) {
		t.Parallel()
		req := httptest.NewRequest("GET", "/api/export/csv", nil)
		req.Header.Set("Origin", allowed)
		rr := httptest.NewRecorder()
		h.ServeHTTP(rr, req)

		if acao := rr.Header().Get("Access-Control-Allow-Origin"); acao != allowed {
			t.Errorf("Access-Control-Allow-Origin = %q, want %q", acao, allowed)
		}
	})
}

